UPDATE public.questions SET
  stimulus_text = 'The author of the text suggests that the first-time homebuyers are primarily motivated by a particular financial concern. The author writes, "The first-time homebuyer typically focuses on the price tag and considers the long-term financial consequences of the purchase, such as the mortgage interest rate and property taxes." What is the financial concern that the author describes as being of primary importance to first-time homebuyers?',
  question_text = 'The author of the passage implies that the most important factor for first-time homebuyers is',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"finding a house that is within their budget.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"securing a mortgage with a low interest rate.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"understanding the overall costs of homeownership.","is_correct":true,"explanation":"Choice C matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"minimizing the amount of property taxes they pay.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'C',
  explanation = 'The passage states that the first-time homebuyer focuses on "the price tag" and considers the "long-term financial consequences of the purchase." This suggests that the most important factor for first-time homebuyers is understanding the overall costs of homeownership, which includes the price, mortgage interest rates, and property taxes. The passage doesn’t directly state that a low interest rate is the most important concern. This makes choice B incorrect. While the passage also mentions property taxes, it doesn’t suggest that these are the most important factor for first-time homebuyers, which makes choice D incorrect. Choice A is incorrect because the passage focuses on long-term financial consequences, not just the purchase price. The passage states that "The author of the text suggests that the first-time homebuyers are primarily motivated by a particular financial concern…", which is the textual anchor for eliminating weaker choices. Choice C is correct because it aligns with that evidence: understanding the overall costs of homeownership.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
